const trigger = $input.first().json.body;
const {
  owner, repo,
  system_prompt_path,
  skills_paths = '',
  base_branch = 'main',
  max_logs = 5,
} = trigger;

const { accessToken: github_token } = await this.getCredentials('githubApi');

const hdr = {
  'Authorization': 'token ' + github_token,
  'Accept': 'application/vnd.github+json',
  'X-GitHub-Api-Version': '2022-11-28',
};
const base = 'https://api.github.com/repos/' + owner + '/' + repo + '/contents';
const dec = b64 => Buffer.from((b64 || '').replace(/\n/g, ''), 'base64').toString('utf8');
const get = url => this.helpers.httpRequest({ method: 'GET', url: url + '?ref=' + encodeURIComponent(base_branch), headers: hdr });

const skillPaths = skills_paths.split(/[,\n]/).map(s => s.trim()).filter(Boolean);
const agentFolder = system_prompt_path.split('/').slice(0, -1).join('/');
const logsPath = agentFolder + '/evals/logs';

const [spResp, ...skillResps] = await Promise.all([
  get(base + '/' + system_prompt_path),
  ...skillPaths.map(p => get(base + '/' + p).catch(() => null)),
]);

const rawSp = dec(spResp.content);
const spSha = spResp.sha;
const qmatch = rawSp.match(/<!--\s*QUALITY_SCORE[\s\S]*?-->\s*\n*/);
const qualityHeader = qmatch ? qmatch[0] : '';
const cleanSp = rawSp.replace(/<!--\s*QUALITY_SCORE[\s\S]*?-->\s*\n*/g, '').trim();

const skills = skillPaths.map((p, i) => {
  const r = skillResps[i];
  if (!r) return null;
  return { path: p, content: dec(r.content), sha: r.sha };
}).filter(Boolean);

let recentLogs = [];
try {
  const dir = await get(base + '/' + logsPath);
  if (Array.isArray(dir)) {
    const entries = dir
      .filter(e => e.type === 'file' && e.name.endsWith('.json'))
      .sort((a, b) => b.name.localeCompare(a.name))
      .slice(0, Number(max_logs) || 5);
    const fetched = await Promise.all(
      entries.map(e =>
        get(base + '/' + e.path)
          .then(r => JSON.parse(dec(r.content)))
          .catch(() => null)
      )
    );
    recentLogs = fetched.filter(Boolean);
  }
} catch (_) {}

const logsText = recentLogs.length === 0
  ? '(no eval logs available yet)'
  : recentLogs.map(log => {
      const lines = [
        '\n=== Run: ' + log.run_id + ' | ' + log.evaluated_at +
        ' | Success rate: ' + (log.stats && log.stats.success_rate) + '% ==='
      ];
      (log.games || []).forEach(g => {
        lines.push('\n--- Game #' + g.id + ': ' + (g.success ? 'SUCCESS' : 'FAILED') +
                   ' in ' + g.iterations + ' iterations ---');
        (g.transcript || []).forEach(t =>
          lines.push((t.role === 'agent' ? 'Agent' : 'User') + ': ' + t.text)
        );
      });
      return lines.join('\n');
    }).join('\n\n---\n\n');

const skillsText = skills.map(s => '### ' + s.path + '\n\n' + s.content).join('\n\n---\n\n');

const contentMap = Object.assign(
  { [system_prompt_path]: { content: cleanSp, sha: spSha } },
  ...skills.map(s => ({ [s.path]: { content: s.content, sha: s.sha } }))
);

return [{ json: {
  owner, repo, base_branch, github_token,
  system_prompt_path, skill_paths: skillPaths,
  qualityHeader, contentMap,
  llmInput:
    '## System Prompt (' + system_prompt_path + ')\n\n' + cleanSp + '\n\n' +
    (skillsText ? '## Skill Files\n\n' + skillsText + '\n\n' : '') +
    '## Recent Conversation Logs\n\n' + logsText,
} }];

const llmOutput = $json.text || $json.output || '';
const ctx = $('Fetch All Content').first().json;

let improvements;
try {
  const m = llmOutput.match(/\[[\s\S]*\]/);
  improvements = m ? JSON.parse(m[0]) : [];
} catch(e) {
  improvements = [];
}

if (!improvements.length) {
  throw new Error('Analysis found no actionable improvements — no PR will be created.');
}

return improvements.map(imp => {
  const fileData = ctx.contentMap[imp.path];
  if (!fileData) return null;
  return { json: {
    path: imp.path,
    change_summary: imp.change_summary || 'Improvement',
    instructions: imp.instructions,
    original_content: fileData.content,
    original_sha: fileData.sha,
    owner: ctx.owner,
    repo: ctx.repo,
    base_branch: ctx.base_branch,
    github_token: ctx.github_token,
    system_prompt_path: ctx.system_prompt_path,
    qualityHeader: ctx.qualityHeader,
  } };
}).filter(Boolean);

