const llmItems = $input.all();
const origItems = $('Parse & Fan Out').all();

const first = origItems[0].json;
const ts = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
const branchName = 'chore/improve-agent-' + ts;

const files = llmItems.map((it, i) => {
  const orig = origItems[i].json;
  let newContent = (it.json.text || it.json.output || '').trim();
  if (orig.path === orig.system_prompt_path && orig.qualityHeader) {
    newContent = orig.qualityHeader + '\n' + newContent;
  }
  return {
    path: orig.path,
    contentBase64: Buffer.from(newContent, 'utf8').toString('base64'),
    sha: orig.original_sha,
    change_summary: orig.change_summary,
  };
});

const changedFiles = files.map(f => '- `' + f.path + '`: ' + f.change_summary).join('\n');
const count = files.length;
const prTitle = 'chore: AI-driven agent improvement (' + count + ' file' + (count > 1 ? 's' : '') + ')';
const prBody = [
  '## Summary',
  '',
  'Automated improvements generated from eval log analysis.',
  '',
  '## Files Changed',
  '',
  changedFiles,
  '',
  '## Review Checklist',
  '',
  '- [ ] Each change addresses a specific observed failure pattern',
  '- [ ] Core agent mission and rules are unchanged',
  '- [ ] Eval will run automatically on this PR',
].join('\n');

return [{ json: {
  owner: first.owner,
  repo: first.repo,
  base_branch: first.base_branch,
  branchName,
  prTitle,
  prBody,
  files,
} }];

const meta = $('Collect & Prep').first().json;
return meta.files.map(f => ({ json: {
  owner: meta.owner,
  repo: meta.repo,
  branchName: meta.branchName,
  path: f.path,
  contentBase64: f.contentBase64,
  sha: f.sha,
} }));
